sql:
SELECT image_id, emotion
FROM image_emotions
WHERE emotion = 'sad';

SELECT model_id, training_data, training_labels, training_status, training_start_time, training_end_time
FROM model_training
WHERE model_id = 1;

SELECT COUNT(*) 
FROM text_inputs 
WHERE client_id = 1 AND text_type = 'feedback';

SELECT 
    (SELECT COUNT(*) FROM clients) AS num_clients, 
    (SELECT AVG(image_size) FROM images) AS avg_image_size;

SELECT emotion
FROM image_emotions
WHERE image_id = 0;

SELECT text 
FROM text_inputs
WHERE client_id = 1;

SELECT client_name 
FROM clients 
WHERE client_id = (
  SELECT MAX(client_id) 
  FROM clients
);

SELECT sentiment, sentiment_intensity
FROM sentiments
WHERE text_id = 0 AND sentiment_confidence > 0.7;

SELECT COUNT(DISTINCT sentiment) AS total_unique_sentiments
FROM sentiments
WHERE text_id = 1;

SELECT AVG(confidence) AS average_emotion_confidence
FROM image_emotions
WHERE model_id = 0;

SELECT images.image_id, images.image_path, images.image_type, clients.client_name
FROM images
INNER JOIN clients ON images.client_id = clients.client_id;
